import React, { useState } from 'react';
import accessService from '../services/accessService';
import { useParams, useNavigate } from 'react-router-dom';
import { MapContainer, TileLayer, Marker, useMapEvents } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
function GrantAccess() {
  const { fileId } = useParams();
  const [userEmail, setUserEmail] = useState('');
  const [role, setRole] = useState('read');
  const [expiry, setExpiry] = useState('');
  const [location, setLocation] = useState(null);
  const [radius, setRadius] = useState('100');
  const navigate = useNavigate();
  const submit = async (e) => {
    e.preventDefault();
    try {
      await accessService.grant({ fileId, userEmail, role, expiry_time: expiry, geo_lat: location ? location.lat : null, geo_lon: location ? location.lng : null, geo_radius_m: radius ? Number(radius) : null });
      alert('Granted');
      navigate('/dashboard');
    } catch (e) {
      alert('Failed');
    }
  };
  const defaultCenter = { lat: 18.5204, lng: 73.8567 };
  const markerIcon = new L.Icon({
    iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
    iconSize: [25, 41],
    iconAnchor: [12, 41],
    popupAnchor: [1, -34],
    shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
    shadowSize: [41, 41]
  });
  function LocationMarker() {
    useMapEvents({
      click(e) {
        setLocation({ lat: e.latlng.lat, lng: e.latlng.lng });
      }
    });
    return location ? <Marker position={location} icon={markerIcon} /> : null;
  }
  return (
    <div className="min-h-screen bg-gradient-to-br from-green-50 via-blue-100 to-purple-50 flex flex-col items-center justify-center p-8">
      <div className="w-full max-w-2xl bg-white rounded-3xl shadow-2xl p-10">
        <div className="flex items-center gap-3 mb-4">
          <span className="text-4xl">🔑</span>
          <h2 className="text-3xl font-extrabold text-green-700 tracking-tight">Grant Access for File ID: {fileId}</h2>
        </div>
        <form onSubmit={submit} className="space-y-6">
          <div>
            <label className="block text-base text-gray-700 mb-1 font-bold">User Email</label>
            <input required placeholder="User Email" value={userEmail} onChange={e => setUserEmail(e.target.value)} className="w-full p-3 border-2 border-green-300 focus:border-blue-400 rounded-xl focus:outline-none transition" />
          </div>
          <div>
            <label className="block text-base text-gray-700 mb-1 font-bold">Role</label>
            <select value={role} onChange={e => setRole(e.target.value)} className="w-full p-3 border-2 border-green-300 focus:border-blue-400 rounded-xl focus:outline-none transition">
              <option value="read">🔎 Read</option>
              <option value="download">⬇️ Download</option>
              <option value="share">🔗 Share</option>
            </select>
          </div>
          <div>
            <label className="block text-base text-gray-700 mb-1 font-bold">Expiry</label>
            <input type="datetime-local" value={expiry} onChange={e => setExpiry(e.target.value)} className="w-full p-3 border-2 border-green-300 focus:border-blue-400 rounded-xl focus:outline-none transition" />
          </div>
          {/* Geofence Section */}
          <div className="pt-4 border-t-2 border-green-100">
            <h4 className="text-lg font-bold text-blue-600 mb-2 flex items-center gap-2">📍 Geofence (Optional)</h4>
            <div className="mb-2" style={{ height: '220px', width: '100%' }}>
              <MapContainer center={defaultCenter} zoom={10} style={{ height: '100%', width: '100%', borderRadius: 14, overflow: 'hidden', border: '2px solid #cbd5e1' }}>
                <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" attribution="&copy; OpenStreetMap contributors" />
                <LocationMarker />
              </MapContainer>
            </div>
            <div className="flex gap-2">
              <input type="number" min="10" step="10" placeholder="Radius (meters)" value={radius} onChange={e => setRadius(e.target.value)} className="w-2/3 p-3 border-2 border-green-300 focus:border-blue-400 rounded-xl focus:outline-none transition" />
              <span className="inline-block self-center text-gray-500">meters</span>
            </div>
            {location && (
              <div className="text-sm text-green-700 mt-2">Selected: lat {location.lat.toFixed(5)}, lon {location.lng.toFixed(5)}</div>
            )}
          </div>
          <button className="bg-gradient-to-r from-green-400 via-blue-500 to-purple-500 hover:from-green-500 hover:to-purple-700 text-white px-6 py-3 rounded-2xl shadow-lg font-bold text-lg w-full transition-all duration-150">Grant Access</button>
        </form>
      </div>
    </div>
  );
}
export default GrantAccess;
